sql:
SELECT COUNT(survey_id) AS number_of_surveys
FROM surveys
WHERE survey_year = 2023;

SELECT total_responses 
FROM surveys 
WHERE survey_id = 1;

SELECT survey_year, total_responses
FROM surveys
ORDER BY survey_year DESC;

SELECT SUM(total_positive) AS total_positive_responses
FROM response_summary
WHERE survey_id = 1;

SELECT response_id, response_date, strongly_agree, positive_answers
FROM responses
ORDER BY response_date DESC;

SELECT survey_category, AVG(total_responses) AS average_responses
FROM surveys
GROUP BY survey_category;

SELECT AVG(positive_answers) AS average_positive_answers
FROM responses
WHERE survey_id = 1 AND question_id = 0;

SELECT total_responses
FROM surveys
WHERE survey_id = 1;

external_knowledge:
- "category of participants" refers to the demographic group (e.g., students, faculty, staff).;
- "replies" refers to the individual responses given to the survey questions. Each reply is uniquely identified by a `response_id`.;
- "the first survey" is represented by `survey_id = 1`.;

